import{_ as t,o as a,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const d=JSON.parse('{"title":"Meta AEM View-Through Attribution in Branch","description":"","frontmatter":{"title":"Meta AEM View-Through Attribution in Branch","slug":"meta-aem-view-through-attribution-in-branch"},"headers":[],"relativePath":"account-hub/meta-aem-view-through-attribution-in-branch.md","filePath":"account-hub/meta-aem-view-through-attribution-in-branch.md"}'),i={name:"account-hub/meta-aem-view-through-attribution-in-branch.md"};function n(u,e,h,l,s,c){return a(),o("div",null,[...e[0]||(e[0]=[r('<p>We&#39;re excited to share an update on our ongoing partnership with Meta, designed to give you a more complete and accurate view of your iOS campaign performance.</p><p>Starting the week of <strong>October 27th</strong>, Branch will begin supporting view-through results for all <a href="./enable-app-aggregated-event-measurement-support.html">Meta Aggregated Events Measurement (AEM)</a>-eligible iOS App Promotion campaigns.</p><h2 id="what-this-means-for-you" tabindex="-1">What this means for you <a class="header-anchor" href="#what-this-means-for-you" aria-label="Permalink to &quot;What this means for you&quot;">​</a></h2><p>Your Branch-attributed data will now automatically include modeled view-through conversions from AEM campaigns. This provides a fuller, privacy-preserving picture of campaign impact, particularly for upper-funnel or video-heavy creatives, complementing your SKAN and last-click data.</p><h3 id="what-you-will-need-to-do" tabindex="-1">What you will need to do <a class="header-anchor" href="#what-you-will-need-to-do" aria-label="Permalink to &quot;What you will need to do&quot;">​</a></h3><p>The best news? No action is needed on your end!</p><p>Since your app is already compliant with Meta’s App Measurement Model (AMM) terms, Branch will automatically integrate these AEM signals into your attribution waterfall. You will see these eligible view-through results automatically appear in your Daily, Custom, and Scheduled Log Exports as the feature rolls out.</p>',7)])])}const m=t(i,[["render",n]]);export{d as __pageData,m as default};
